function validateForm() {
  const pickup = document.getElementById("pickupAddress").value.trim();
  const dropoff = document.getElementById("dropoffAddress").value.trim();
  const passengers = document.getElementById("passengers").value;
  if (pickup.length < 3) {
    requestAnimationFrame(() => document.getElementById("pickupAddress").focus());
    return false;
  }
  if (dropoff.length < 3) {
    requestAnimationFrame(() => document.getElementById("dropoffAddress").focus());
    return false;
  }
  if (!passengers || Number(passengers) < 1) {
    requestAnimationFrame(() => document.getElementById("passengers").focus());
    return false;
  }
  return true;
}

function trackGoogleAdsConversion() {
  console.log("Google Ads Conversion Triggered");
}

document.addEventListener("DOMContentLoaded", () => {
  const form = document.getElementById("quote-form");
  const successMsg = document.getElementById("success-message");
  const resetBtn = document.getElementById("reset-form-btn");

  if (form) {
    form.addEventListener("submit", (e) => {
      e.preventDefault();

      const submitBtn = document.getElementById("submitBtn");

      // Basic empty field checks instead of alerts
      if (!validateForm()) return;

      const originalText = submitBtn.innerText;
      submitBtn.disabled = true;
      submitBtn.innerText = "Sending...";

      // Action A: Web3Forms API
      const formData = new FormData(form);
      // Ensure access key is set correctly in FormData
      formData.set("access_key", "c6918289-d59c-41e8-883a-3ac76cde4b6e");
      formData.set("_subject", "New Limo Quote Request!");
      formData.set("from_name", "Luxury Limo Detroit Notifications");

      // Action B: WhatsApp Routing
      let waText = "New Booking Request!\n\n";
      waText += `Name: ${formData.get("customerName") || ''}\n`;
      waText += `Phone: ${formData.get("phone") || ''}\n`;
      waText += `Passengers: ${formData.get("passengers") || ''}\n`;
      waText += `Vehicle: ${formData.get("vehicleType") || ''}\n`;
      waText += `Service: ${formData.get("serviceType") || ''}\n`;
      waText += `Pickup: ${formData.get("pickupAddress") || ''}\n`;
      waText += `Dropoff: ${formData.get("dropoffAddress") || ''}\n`;
      waText += `Date: ${formData.get("date") || ''}\n`;
      waText += `Time: ${formData.get("time") || ''}\n`;

      const formattedMessage = encodeURIComponent(waText);
      const waUrl = 'https://wa.me/15864744195?text=' + formattedMessage;

      // Web3Forms Fetch
      fetch('https://api.web3forms.com/submit', {
        method: 'POST',
        headers: {
          'Accept': 'application/json'
        },
        body: formData
      })
        .then(response => response.json())
        .then(data => {
          if (data.success) {
            console.log("Web3Forms Success:", data);
            // Only open WA if fetch is OK context-wise
            window.open(waUrl, '_blank');

            trackGoogleAdsConversion();

            // Action C: UI Swap
            form.style.display = 'none';
            successMsg.style.display = 'flex';
            form.reset();
          } else {
            console.error("Web3Forms Error:", data);
          }
        })
        .catch(error => {
          console.error("Web3Forms Catch Error:", error);
        })
        .finally(() => {
          submitBtn.disabled = false;
          submitBtn.innerText = originalText;
        });
    });
  }

  // Action D: Reset UI
  if (resetBtn) {
    resetBtn.addEventListener("click", () => {
      successMsg.style.display = 'none';
      form.style.display = 'grid'; // Originally 'grid' or 'block', form defaults to block but form has class 'form-grid' which in CSS assigns display: grid. However, index.html class is form-grid.
    });
  }
});
